module top_module(
  input Vin,
  input Vth,
  input clk,
  input reset,
  output rst_out
);reg obf_bor_ff;

  always @ (posedge clk or negedge reset) begin
    if (!reset) begin
      obf_bor_ff <= 0;
    end else begin
      if (Vin < Vth) begin
        obf_bor_ff <= 1;
      end else begin
        obf_bor_ff <= 0;
      end
    end
  end

  assign rst_out = obf_bor_ff;

endmodule
